import React, { useState, useEffect } from 'react';
import { NotesProvider } from './context/NotesContext';
import Sidebar from './components/Layout/Sidebar';
import SplitLayout from './components/Layout/SplitLayout';
import TopBar from './components/UI/TopBar';
import ErrorBoundary from './components/ErrorBoundary';
import { useNotes } from './context/NotesContext';
import './styles/main.css';

function AppContent() {
  const { currentNote } = useNotes();
  const [showEditor, setShowEditor] = useState(false);
  const [isDesktop, setIsDesktop] = useState(false);

  // Detect screen size
  useEffect(() => {
    const checkScreenSize = () => {
      const width = window.innerWidth;
      const desktop = width >= 769;
      console.log('Screen width:', width, 'Is desktop:', desktop);
      setIsDesktop(desktop);
    };

    checkScreenSize();
    window.addEventListener('resize', checkScreenSize);

    return () => window.removeEventListener('resize', checkScreenSize);
  }, []);

  const handleNoteSelect = () => {
    setShowEditor(true);
  };

  const handleBack = () => {
    setShowEditor(false);
  };

  console.log('Render - isDesktop:', isDesktop, 'showEditor:', showEditor, 'currentNote:', currentNote);

  if (isDesktop) {
    // Desktop: Show both sidebar and editor
    return (
      <div className="app-container desktop-layout">
        <Sidebar />
        {currentNote && <SplitLayout />}
      </div>
    );
  }

  // Mobile: Show either sidebar or editor
  return (
    <div className="app-container mobile-layout">
      {!showEditor ? (
        <Sidebar onNoteSelect={handleNoteSelect} />
      ) : (
        <SplitLayout onBack={handleBack} />
      )}
    </div>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <NotesProvider>
        <AppContent />
      </NotesProvider>
    </ErrorBoundary>
  );
}

export default App;
